import { spawnSync } from "child_process";

import { loadPhoton } from "./photon.js";

type ClipboardModule = {
	hasImage: () => boolean;
	getImageBinary: () => Promise<Array<number>>;
};

let clipboardModule: ClipboardModule | null | undefined;

/**
 * Lazy-load the native clipboard module. Returns null if unavailable.
 * On Linux, requires DISPLAY or WAYLAND_DISPLAY to be set (the Rust
 * library panics without a display server).
 */
async function loadClipboard(): Promise<ClipboardModule | null> {
	if (clipboardModule !== undefined) {
		return clipboardModule;
	}

	// Check display availability on Linux to avoid Rust panic
	if (process.platform === "linux" && !process.env.DISPLAY && !process.env.WAYLAND_DISPLAY) {
		clipboardModule = null;
		return null;
	}

	try {
		const mod = await import("@mariozechner/clipboard");
		clipboardModule = mod.default ?? mod;
		return clipboardModule;
	} catch {
		clipboardModule = null;
		return null;
	}
}

